import { useQuery } from '@tanstack/react-query';
import React from 'react'
import { useParams } from 'react-router-dom'
import { Img_URL, fetchSearch } from '../../utils/fetchApi';

const Search = () => {
  const serachTerm= useParams();

  const {isLoading,isError,error,data:searched}=useQuery({
    queryKey:['searched'],
    queryFn: ()=> fetchSearch(`${serachTerm}`)
    .then((result)=> result),
  })


  if (isLoading) {
    return (
      <div className="loading">
        <h1>Loading</h1>
      </div>
    );
  } else if (isError) {
    return (
      <div className="error">
        <p>{error.message}</p>
      </div>
    );
  }
  return (
    <section className='search'>
      {
        searched.map((item)=>(
      <div>
        <img src={`${Img_URL}${item.poster_path}`} alt="?" />
        <p>{item.overview}</p>
      </div>
        ))
      }
    </section>
  )
}

export default Search
